function doPost(r){try{var t=SpreadsheetApp.getActiveSpreadsheet().getActiveSheet(),e=JSON.parse(r.postData.contents),o=new Date,s=e.email||"",c=e.name||"",u=e.source||"Website";if(!s)return ContentService.createTextOutput(JSON.stringify({status:"error",message:"Email is required"})).setMimeType(ContentService.MimeType.JSON);for(var a=t.getDataRange().getValues(),n=1;n<a.length;n++)if(a[n][0]===s)return ContentService.createTextOutput(JSON.stringify({status:"success",message:"Email already subscribed"})).setMimeType(ContentService.MimeType.JSON);return t.appendRow([s,c,o,u]),ContentService.createTextOutput(JSON.stringify({status:"success",message:"Subscription saved successfully"})).setMimeType(ContentService.MimeType.JSON)}catch(i){return Logger.log("Error: "+i.toString()),ContentService.createTextOutput(JSON.stringify({status:"error",message:i.toString()})).setMimeType(ContentService.MimeType.JSON)}}function test(){var r={email:"test@example.com",name:"Test User",source:"Test"},t={postData:{contents:JSON.stringify(r)}},e=doPost(t);Logger.log(e.getContent())}
